mapper.select:
SELECT *
FROM attendance
WHERE work_date = #{workDate} AND user_id = #{userId}

mapper.update:
UPDATE attendance
SET clock_in = #{clockIn},
    clock_out = #{clockOut},
    modified_by = #{modifiedBy},
    modified_at = #{modifiedAt}
WHERE user_id = #{userId}
  AND work_date = #{workDate}
